using System.Data;
using Dapper;
using Valora.Application.Contracts;
namespace Valora.Infrastructure.Repositories;
public sealed class CommunicationRepository(IDbConnectionFactory f):ICommunicationRepository{ public async Task AddEmailJobAsync(Guid responseId,string toEmail,string status){using var c=f.Create(); await c.ExecuteAsync("INSERT INTO valorapesquisa.email_jobs(response_id,recipient_email,subject,template_key,status) VALUES (@responseId,@toEmail,'Valora Insight™ - Seu diagnóstico está pronto','result-ready',@status)",new{responseId,toEmail,status});} public async Task<IReadOnlyList<dynamic>> ListAsync(Guid? organizationId=null){using var c=f.Create(); return (await c.QueryAsync("SELECT * FROM valorapesquisa.communications WHERE (@organizationId IS NULL OR organization_id=@organizationId) ORDER BY created_at DESC LIMIT 100",new{organizationId})).ToList();} public async Task CreateEmailJobAsync(Guid organizationId,Guid responseId,string recipientEmail,string status,IDbTransaction tx){await tx.Connection!.ExecuteAsync("INSERT INTO valorapesquisa.email_jobs(organization_id,response_id,recipient_email,subject,template_key,status,payload_json) VALUES (@organizationId,@responseId,@recipientEmail,'Valora Insight™ - Seu diagnóstico está pronto','result-ready',@status,jsonb_build_object('responseId',@responseId))",new{organizationId,responseId,recipientEmail,status},tx);} public async Task CreateCommunicationAsync(Guid organizationId,Guid surveyId,Guid responseId,string channel,string eventType,string status,string? recipientMasked,IDbTransaction tx){await tx.Connection!.ExecuteAsync("INSERT INTO valorapesquisa.communications(organization_id,survey_id,response_id,channel,event_type,status,recipient_masked) VALUES (@organizationId,@surveyId,@responseId,@channel,@eventType,@status,@recipientMasked)",new{organizationId,surveyId,responseId,channel,eventType,status,recipientMasked},tx);}}
